templates.formula:
\begin{align}
{\mathrm enhanced\ basic\ ATK\ DMG} & = 100%\ total\ physical\ ATK + 200%\ total\ magic\ power\ + \Bigl\{total\ rage \times \bigl[10 + (0.2 \times hero\ lv.) \bigr]\Bigr\} \\
healing\ effect & = 8 \times rage \\
{\mathrm where}\ 25 & \geq total\ rage \geq 100\\
\end{align}

